import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CalculatorTest {

    private final Calculator calculator = new Calculator();

    @Test
    public void testAddition() {
        assertEquals(5, calculator.add(2, 3));
        assertEquals(-1, calculator.add(-2, 1));
        assertEquals(0, calculator.add(0, 0));
    }

    @Test
    public void testSubtraction() {
        assertEquals(1, calculator.subtract(5, 4));
        assertEquals(-3, calculator.subtract(-2, 1));
        assertEquals(0, calculator.subtract(0, 0));
    }

    @Test
    public void testMultiplication() {
        assertEquals(6, calculator.multiply(2, 3));
        assertEquals(-2, calculator.multiply(-1, 2));
        assertEquals(0, calculator.multiply(0, 5));
    }

    @Test
    public void testDivision() {
        assertEquals(2.0, calculator.divide(6, 3));
        assertThrows(IllegalArgumentException.class, () -> calculator.divide(1, 0));
        assertEquals(-2.5, calculator.divide(-5, 2));
    }
}

from cement import App, Controller, ex
import logging

class BaseController(Controller):
    class Meta:
        label = 'base'
        description = 'A basic arithmetic calculator application.'

    @ex(help='Add two numbers')
    def add(self):
        try:
            a = float(self.app.pargs.a)
            b = float(self.app.pargs.b)
            result = a + b
            print(f"The result of addition is: {result}")
            self._log_operation('add', a, b, result)
        except ValueError:
            print("Invalid input: Please provide two numbers.")

    @ex(help='Subtract two numbers')
    def subtract(self):
        try:
            a = float(self.app.pargs.a)
            b = float(self.app.pargs.b)
            result = a - b
            print(f"The result of subtraction is: {result}")
            self._log_operation('subtract', a, b, result)
        except ValueError:
            print("Invalid input: Please provide two numbers.")

    @ex(help='Multiply two numbers')
    def multiply(self):
        try:
            a = float(self.app.pargs.a)
            b = float(self.app.pargs.b)
            result = a * b
            print(f"The result of multiplication is: {result}")
            self._log_operation('multiply', a, b, result)
        except ValueError:
            print("Invalid input: Please provide two numbers.")

    @ex(help='Divide two numbers')
    def divide(self):
        try:
            a = float(self.app.pargs.a)
            b = float(self.app.pargs.b)
            if b == 0:
                print("Division by zero error")
                return
            result = a / b
            print(f"The result of division is: {result}")
            self._log_operation('divide', a, b, result)
        except ValueError:
            print("Invalid input: Please provide two numbers.")

    def _log_operation(self, operation, a, b, result):
        logging.info(f"Operation: {operation}, Inputs: {a}, {b}, Result: {result}")

