import { createApp, reactive } from 'whatsup';

const app = createApp();

const state = reactive({
  items: [],
  newItem: '',
  error: null
});

function* App() {
  const addItem = () => {
    if (state.newItem.trim() === '') {
      state.error = 'Item cannot be empty';
      return;
    }
    state.items.push(state.newItem.trim());
    state.newItem = '';
    state.error = null;
  };

  const removeItem = index => {
    state.items.splice(index, 1);
  };

  while (true) {
    yield (
      <div style="margin: 20px;">
        <h1>User-Specified Items</h1>
        <div>
          <input type="text" 
                value={state.newItem} 
                onInput={e => state.newItem = e.target.value} 
                placeholder="Add new item" />
          <button onClick={addItem}>Add</button>
          <span style={{color: 'red'}}>{state.error}</span>
        </div>
        <ul style={{listStyleType: 'none', padding: 0}}>
          {state.items.map((item, index) => (
            <li key={index} 
                style={{padding: '5px', border: '1px solid #ccc', margin: '5px 0'}}>
              {item} 
              <button onClick={() => removeItem(index)} style={{marginLeft: '10px'}}>Remove</button>
            </li>
          ))}
        </ul>
      </div>
    );
  }
}

app.createComponent(App);
