@Path("/log")
public class LoggingService {

    public LoggingService() {
        // Load and configure tinylog
        ConfigurationLoader.getDefaultLoader().loadConfigurations(Configuration.getProperties());
    }

    @POST
    @Path("/info")
    @Consumes(MediaType.APPLICATION_JSON)
    @Produces(MediaType.APPLICATION_JSON)
    public Response logInfo(Map<String, String> data) {
        return log(data, "info");
    }

    @POST
    @Path("/debug")
    @Consumes(MediaType.APPLICATION_JSON)
    @Produces(MediaType.APPLICATION_JSON)
    public Response logDebug(Map<String, String> data) {
        return log(data, "debug");
    }

    @POST
    @Path("/error")
    @Consumes(MediaType.APPLICATION_JSON)
    @Produces(MediaType.APPLICATION_JSON)
    public Response logError(Map<String, String> data) {
        return log(data, "error");
    }

    private Response log(Map<String, String> data, String level) {
        String message = data.get("message");
        if (message == null || message.isEmpty()) {
            return Response.status(Response.Status.BAD_REQUEST)
                    .entity(createErrorResponse("Message is required"))
                    .build();
        }

        try {
            switch (level) {
                case "info":
                    Logger.info(message);
                    break;
                case "debug":
                    Logger.debug(message);
                    break;
                case "error":
                    Logger.error(message);
                    break;
                default:
                    return Response.status(Response.Status.BAD_REQUEST)
                            .entity(createErrorResponse("Invalid log level"))
                            .build();
            }
            return Response.ok(createSuccessResponse("Message logged successfully")).build();
        } catch (Exception e) {
            Logger.error(e);
            return Response.status(Response.Status.INTERNAL_SERVER_ERROR)
                    .entity(createErrorResponse("Logging process encountered an error"))
                    .build();
        }
    }

    private Map<String, String> createErrorResponse(String message) {
        Map<String, String> errorResponse = new HashMap<>();
        errorResponse.put("status", "error");
        errorResponse.put("message", message);
        return errorResponse;
    }

    private Map<String, String> createSuccessResponse(String message) {
        Map<String, String> successResponse = new HashMap<>();
        successResponse.put("status", "success");
        successResponse.put("message", message);
        return successResponse;
    }
}

