use bevy::window::WindowResized;

fn main() {
    App::build()
        .insert_resource(WindowDescriptor {
            title: "Colored Rectangle".to_string(),
            width: 800.,
            height: 600.,
            ..Default::default()
        })
        .add_plugins(DefaultPlugins)
        .add_startup_system(setup.system())
        .add_system(change_color_on_input.system())
        .add_system(resize_event_listener.system())
        .run();
