struct ColoredRectangle;

fn setup(mut commands: Commands, mut materials: ResMut<Assets<ColorMaterial>>, mut windows: ResMut<Windows>) {
    commands.spawn_bundle(OrthographicCameraBundle::new_2d());

    commands
        .spawn_bundle(SpriteBundle {
            material: materials.add(Color::rgb(0.5, 0.5, 1.0).into()),
            sprite: Sprite::new(Vec2::new(100.0, 100.0)),
            ..Default::default()
        })
        .insert(ColoredRectangle);

    let window = windows.get_primary_mut().unwrap();
    window.set_resizable(true);
}

fn change_color_on_input(
    mut materials: ResMut<Assets<ColorMaterial>>, 
    keyboard_input: Res<Input<KeyCode>>, 
    query: Query<&Handle<ColorMaterial>, With<ColoredRectangle>>) {

    for handle in query.iter() {
        let material = materials.get_mut(handle).unwrap();
        if keyboard_input.pressed(KeyCode::R) {
            material.color = Color::rgb(1.0, 0.0, 0.0);
        } else if keyboard_input.pressed(KeyCode::G) {
            material.color = Color::rgb(0.0, 1.0, 0.0);
        } else if keyboard_input.pressed(KeyCode::B) {
            material.color = Color::rgb(0.0, 0.0, 1.0);
        }
    }
}

fn resize_event_listener(mut resize_reader: EventReader<WindowResized>) {
    for event in resize_reader.iter() {
        println!("Window resized to {}x{}", event.width, event.height);
    }
}

