const express = require('express');
const app = express();
app.use(express.json());

let todos = [];
let idCounter = 1;

// Middleware for input validation
const validateTodoInput = (req, res, next) => {
  const { title } = req.body;
  if (!title || typeof title !== 'string' || title.trim() === '') {
    return res.status(400).json({ error: 'Invalid input: Title is required and must be a non-empty string.' });
  }
  next();
};

// Error-handling middleware
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({ error: 'Internal server error' });
});

// Create a new todo
app.post('/todos', validateTodoInput, (req, res) => {
  const { title } = req.body;
  const newTodo = { id: idCounter++, title, completed: false };
  todos.push(newTodo);
  res.status(201).json(newTodo);
});

// Read all todos
app.get('/todos', (req, res) => {
  res.json(todos);
});

// Read a specific todo by id
app.get('/todos/:id', (req, res) => {
  const todo = todos.find(t => t.id === parseInt(req.params.id));
  if (!todo) return res.status(404).json({ error: 'Todo not found' });
  res.json(todo);
});

// Update a todo by id
app.put('/todos/:id', validateTodoInput, (req, res) => {
  const todo = todos.find(t => t.id === parseInt(req.params.id));
  if (!todo) return res.status(404).json({ error: 'Todo not found' });
  const { title, completed } = req.body;
  if (typeof completed !== 'undefined' && typeof completed !== 'boolean') {
    return res.status(400).json({ error: 'Invalid input: Completed must be a boolean.' });
  }
  todo.title = title;
  if (typeof completed !== 'undefined') {
    todo.completed = completed;
  }
  res.json(todo);
});

// Delete a todo by id
app.delete('/todos/:id', (req, res) => {
  const todoIndex = todos.findIndex(t => t.id === parseInt(req.params.id));
  if (todoIndex === -1) return res.status(404).json({ error: 'Todo not found' });
  const removedTodo = todos.splice(todoIndex, 1);
  res.json(removedTodo);
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

use cot::{router, Application, Body, Context, Request, Response, Result};
use serde::{Deserialize, Serialize};
use serde_json::json;
use std::sync::{Arc, Mutex};

#[derive(Serialize, Deserialize, Clone)]
struct Item {
    id: usize,
    name: String,
}

#[derive(Clone)]
struct State {
    items: Arc<Mutex<Vec<Item>>>,
}

async fn get_items(ctx: &mut Context<State>) -> Result<Response> {
    let items = ctx.state().items.lock().unwrap();
    let response_body = Body::from_json(&*items)?;
    Ok(Response::new(200).with_body(response_body))
}

async fn add_item(mut req: Request<State>) -> Result<Response> {
    let new_item: Result<Item, _> = req.body_json().await;
    match new_item {
        Ok(item) => {
            let mut items = req.state().items.lock().unwrap();
            items.push(item);
            Ok(Response::new(201).with_body(Body::from_json(&json!({"status": "success", "item": item}))?))
        }
        Err(_) => Ok(Response::new(400).with_body(Body::from_json(
            &json!({"error": "Invalid input, please ensure the input is in the correct format and try again"}),
        )?)),
    }
}

#[tokio::main]
async fn main() -> Result<()> {
    let state = State {
        items: Arc::new(Mutex::new(Vec::new())),
    };

    let app = Application::new(state, router! {
        "/items" => {
            GET => get_items,
            POST => add_item,
        }
    });

    app.run("127.0.0.1:8080").await
}

