import org.tinylog.Logger;
import java.util.HashMap;
import java.util.Map;

public class UserStoreApp {
    private static final Map<Integer, String> userStore = new HashMap<>();
    private static int idCounter = 1;

    public static void main(String[] args) {
        try {
            createUser("Alice");
            createUser("Bob");

            retrieveUser(1);
            updateUser(1, "Alice Smith");
            deleteUser(2);

            retrieveUser(3); // Non-existent user for exception handling
        } catch (Exception e) {
            Logger.error(e, "An error occurred during operations");
        }
    }

    private static void createUser(String name) {
        int id = idCounter++;
        userStore.put(id, name);
        Logger.info("Created user [{}] with ID [{}]", name, id);
    }

    private static void retrieveUser(int id) {
        if (userStore.containsKey(id)) {
            String name = userStore.get(id);
            Logger.info("Retrieved user [{}] with ID [{}]", name, id);
        } else {
            Logger.warn("Attempted to retrieve non-existent user with ID [{}]", id);
            throw new IllegalArgumentException("User not found");
        }
    }

    private static void updateUser(int id, String newName) {
        if (userStore.containsKey(id)) {
            userStore.put(id, newName);
            Logger.info("Updated user ID [{}] to new name [{}]", id, newName);
        } else {
            Logger.warn("Attempted to update non-existent user with ID [{}]", id);
            throw new IllegalArgumentException("User not found");
        }
    }

    private static void deleteUser(int id) {
        if (userStore.containsKey(id)) {
            String name = userStore.remove(id);
            Logger.info("Deleted user [{}] with ID [{}]", name, id);
        } else {
            Logger.warn("Attempted to delete non-existent user with ID [{}]", id);
            throw new IllegalArgumentException("User not found");
        }
    }
}

