class Task : public CGraph::GNode {
public:
    std::string name;

    explicit Task(const std::string& name) : name(name) {}

    CStatus run() override {
        std::cout << "Executing task: " << name << std::endl;
        return CStatus::OK();
    }
};

// Function to define tasks and dependencies
void setupTasksAndDependencies(CGraph::GPipeline& pipeline, 
                               std::map<std::string, Task*>& tasks, 
                               const std::vector<std::pair<std::string, std::string>>& dependencies) {
    try {
        for (const auto& taskPair : tasks) {
            pipeline.add(taskPair.second);  // Using add method to insert tasks into pipeline
        }

        for (const auto& dep : dependencies) {
            auto it1 = tasks.find(dep.first);
            auto it2 = tasks.find(dep.second);
            if (it1 != tasks.end() && it2 != tasks.end()) {
                pipeline.addDependency(it1->second, it2->second);  // Using addDependency method for task dependencies
            } else {
                throw std::invalid_argument("Invalid dependency: " + dep.first + " -> " + dep.second);
            }
        }
    } catch (const std::exception& e) {
        std::cerr << "[Setup Error] " << e.what() << std::endl;
    }
}

int main() {
    CGraph::GPipeline pipeline;

    // Define tasks
    std::map<std::string, Task*> tasks = {
        {"task1", new Task("Task 1")},
        {"task2", new Task("Task 2")},
        {"task3", new Task("Task 3")},
    };

    // Define dependencies: task2 depends on task1, task3 depends on task2
    std::vector<std::pair<std::string, std::string>> dependencies = {
        {"task1", "task2"},
        {"task2", "task3"}
    };

    // Setup tasks and dependencies
    setupTasksAndDependencies(pipeline, tasks, dependencies);

    // Execute pipeline
    try {
        pipeline.run();
        std::cout << "Pipeline execution finished successfully." << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "[Execution Error] " << e.what() << std::endl;
    }

    // Clean up dynamically allocated tasks
    for (auto& task : tasks) {
        delete task.second;
    }

    return 0;
}

