// Implement the server
import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.stub.StreamObserver;
import java.util.concurrent.ConcurrentHashMap;
import java.util.Map;
import java.util.logging.Logger;

public class LibraryServer {
    private static final Logger logger = Logger.getLogger(LibraryServer.class.getName());

    private final int port;
    private final Server server;
    private final Map<String, LibraryServiceOuterClass.Book> libraryBooks = new ConcurrentHashMap<>();

    public LibraryServer(int port) {
        this.port = port;
        server = ServerBuilder.forPort(port)
                .addService(new LibraryServiceImpl())
                .build();
    }

    public static void main(String[] args) throws Exception {
        LibraryServer libraryServer = new LibraryServer(50051);
        libraryServer.start();
        libraryServer.blockUntilShutdown();
    }

    private void start() throws Exception {
        server.start();
        logger.info("Server started, listening on " + port);
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.err.println("*** shutting down gRPC server since JVM is shutting down");
            LibraryServer.this.stop();
            System.err.println("*** server shut down");
        }));
    }

    private void stop() {
        if (server != null) {
            server.shutdown();
        }
    }

    private void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    private class LibraryServiceImpl extends LibraryServiceGrpc.LibraryServiceImplBase {

        @Override
        public void addBook(LibraryServiceOuterClass.Book request, StreamObserver<LibraryServiceOuterClass.BookResponse> responseObserver) {
            logger.info("Received request to add book: " + request.getTitle());
            libraryBooks.put(request.getId(), request);
            LibraryServiceOuterClass.BookResponse response = LibraryServiceOuterClass.BookResponse.newBuilder()
                    .setMessage("Book added successfully")
                    .build();
            responseObserver.onNext(response);
            responseObserver.onCompleted();
        }

        @Override
        public void getBookById(LibraryServiceOuterClass.BookId request, StreamObserver<LibraryServiceOuterClass.Book> responseObserver) {
            logger.info("Received request to get book by ID: " + request.getId());
            LibraryServiceOuterClass.Book book = libraryBooks.get(request.getId());
            if (book != null) {
                responseObserver.onNext(book);
                responseObserver.onCompleted();
            } else {
                responseObserver.onError(new RuntimeException("Book not found"));
            }
        }

        @Override
        public void listAllBooks(LibraryServiceOuterClass.Empty request, StreamObserver<LibraryServiceOuterClass.BookList> responseObserver) {
            logger.info("Received request to list all books");
            LibraryServiceOuterClass.BookList books = LibraryServiceOuterClass.BookList.newBuilder()
                    .addAllBooks(libraryBooks.values())
                    .build();
            responseObserver.onNext(books);
            responseObserver.onCompleted();
        }
    }
}

