# Setup logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

books = {}
book_service = Service(name='book', path='/books/{book_id}', description="Book management service")

def log_request(request):
    method = request.method
    endpoint = request.path
    timestamp = datetime.datetime.now()
    logger.info(f"{timestamp} | {method} | {endpoint}")

@book_service.get()
def get_book(request):
    log_request(request)
    book_id = request.matchdict['book_id']
    if book_id in books:
        return books[book_id]
    else:
        request.response.status = 404
        return {'error': 'Book not found'}

@book_service.post()
def create_book(request):
    log_request(request)
    try:
        book_id = request.json_body['id']
        title = request.json_body['title']
        author = request.json_body['author']
    except KeyError as e:
        request.response.status = 400
        return {'error': f'Missing parameter: {str(e)}'}

    if book_id in books:
        request.response.status = 409
        return {'error': 'Book already exists'}

    books[book_id] = {'title': title, 'author': author}
    request.response.status = 201
    return books[book_id]

@book_service.put()
def update_book(request):
    log_request(request)
    book_id = request.matchdict['book_id']
    if book_id not in books:
        request.response.status = 404
        return {'error': 'Book not found'}

    try:
        title = request.json_body['title']
        author = request.json_body['author']
    except KeyError as e:
        request.response.status = 400
        return {'error': f'Missing parameter: {str(e)}'}

    books[book_id].update({'title': title, 'author': author})
    return books[book_id]

@book_service.delete()
def delete_book(request):
    log_request(request)
    book_id = request.matchdict['book_id']
    if book_id in books:
        del books[book_id]
        return Response(status=204)
    else:
        request.response.status = 404
        return {'error': 'Book not found'}

