    config = Configurator(settings=settings)
    config.include("cornice")
    config.scan()
    return config.make_wsgi_app()

from flask import Flask, jsonify, request, abort
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.INFO)

# Sample task data
tasks = []

# Error handler
@app.errorhandler(400)
def bad_request(error):
    return jsonify({'error': 'Bad request'}), 400

@app.errorhandler(404)
def not_found(error):
    return jsonify({'error': 'Not found'}), 404

# Input validation
def validate_task_data(data):
    if 'title' not in data or not isinstance(data['title'], str):
        abort(400)
    return True

# Routes
@app.route('/tasks', methods=['GET'])
def get_tasks():
    app.logger.info("Handling GET /tasks")
    return jsonify({'tasks': tasks})

@app.route('/tasks', methods=['POST'])
def create_task():
    app.logger.info("Handling POST /tasks")
    if not request.json:
        abort(400)
    if not validate_task_data(request.json):
        abort(400)

    task = {
        'id': len(tasks) + 1,
        'title': request.json['title']
    }
    tasks.append(task)
    return jsonify({'task': task}), 201

@app.route('/tasks/<int:task_id>', methods=['PUT'])
def update_task(task_id):
    app.logger.info(f"Handling PUT /tasks/{task_id}")
    task = next((task for task in tasks if task['id'] == task_id), None)
    if not task:
        abort(404)
    if not request.json:
        abort(400)
    if not validate_task_data(request.json):
        abort(400)

    task['title'] = request.json.get('title', task['title'])
    return jsonify({'task': task})

@app.route('/tasks/<int:task_id>', methods=['DELETE'])
def delete_task(task_id):
    app.logger.info(f"Handling DELETE /tasks/{task_id}")
    task = next((task for task in tasks if task['id'] == task_id), None)
    if not task:
        abort(404)
    tasks.remove(task)
    return jsonify({'result': 'Task deleted'})

if __name__ == '__main__':
    app.run(port=5000)

from flask import Flask, request, jsonify
import os
import time
from werkzeug.utils import secure_filename

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024  # 16MB

ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif', 'pdf', 'txt'}

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

if not os.path.exists(app.config['UPLOAD_FOLDER']):
    os.makedirs(app.config['UPLOAD_FOLDER'])

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    if file and allowed_file(file.filename):
        timestamp = int(time.time())
        filename = secure_filename(f"{timestamp}_{file.filename}")
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)
        return jsonify({'file_path': file_path, 'timestamp': timestamp}), 201
    else:
        return jsonify({'error': 'Unsupported file type or file too large'}), 400

@app.route('/files', methods=['GET'])
def list_files():
    files = []
    for filename in os.listdir(app.config['UPLOAD_FOLDER']):
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        upload_time = os.path.getctime(file_path)
        files.append({'filename': filename, 'file_path': file_path, 'timestamp': upload_time})
    return jsonify(files), 200

if __name__ == '__main__':
    app.run(debug=True)

import org.tinylog.Logger;
import org.tinylog.configuration.Configuration;
import org.tinylog.writers.FileWriter;

import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.time.LocalDateTime;
import java.util.HashMap;
import java.util.Map;

public class UserRegistrationProcessor {

    static {
        Configuration.set("writer", FileWriter.class.getName());
        Configuration.set("writer.file", "logs/user_registration_{date}.log");
        Configuration.set("writer.rotate", "daily");
        Configuration.set("format", "{level}\t{date}\t{method}\t{message}");
    }

    public static void main(String[] args) {
        processCsvFile("user_registrations.csv");
    }

    public static void processCsvFile(String filePath) {
        String line;
        try (BufferedReader br = new BufferedReader(new FileReader(filePath))) {
            while ((line = br.readLine()) != null) {
                String[] fields = line.split(",");
                Map<String, String> record = new HashMap<>();
                record.put("name", fields[0].trim());
                record.put("email", fields[1].trim());

                if (validateRecord(record)) {
                    Logger.info("Registration success for user: " + record.get("name"));
                } else {
                    Logger.error("Registration failed for record with missing fields: " + line);
                }
            }
        } catch (IOException e) {
            Logger.error("Error reading CSV file: " + e.getMessage());
        }
    }

    private static boolean validateRecord(Map<String, String> record) {
        return record.containsKey("name") && !record.get("name").isEmpty()
                && record.containsKey("email") && !record.get("email").isEmpty();
    }
}

