use bevy::prelude::*;
use bevy::ecs::schedule::SystemSet;

#[derive(Component)]
struct Player {
    health: i32,
}

#[derive(Component)]
struct Obstacle;

#[derive(Component)]
struct Velocity(Vec3);

#[derive(Component)]
struct Collider;

#[derive(Default)]
struct GameState {
    in_game: bool,
    game_over: bool,
}

fn main() {
    App::build()
        .insert_resource(WindowDescriptor {
            title: "2D Game Prototype".to_string(),
            width: 800.0,
            height: 600.0,
            ..Default::default()
        })
        .insert_resource(GameState::default())
        .add_plugins(DefaultPlugins)
        .add_startup_system(setup.system())
        .add_system(input_control.system().with_run_criteria(on_game_criteria.system()))
        .add_system(movement.system().with_run_criteria(on_game_criteria.system()))
        .add_system(collision_detection.system().with_run_criteria(on_game_criteria.system()))
        .add_system(update_health.system().with_run_criteria(on_game_criteria.system()))
        .add_system_set_to_stage(CoreStage::PostUpdate, SystemSet::new().with_system(check_game_over.system()))
        .add_system(show_start_screen.system().with_run_criteria(on_start_criteria.system()))
        .add_system(show_game_over_screen.system().with_run_criteria(on_game_over_criteria.system()))
        .run();
}

fn setup(mut commands: Commands, mut game_state: ResMut<GameState>, asset_server: Res<AssetServer>, mut materials: ResMut<Assets<ColorMaterial>>) {
    commands.spawn_bundle(OrthographicCameraBundle::new_2d());
    game_state.in_game = false;
    game_state.game_over = false;

    // Add player
    commands
        .spawn_bundle(SpriteBundle {
            material: materials.add(Color::rgb(0.0, 0.5, 1.0).into()),
            transform: Transform::from_xyz(0.0, 0.0, 10.0),
            sprite: Sprite::new(Vec2::new(30.0, 30.0)),
            ..Default::default()
        })
        .insert(Player { health: 100 })
        .insert(Velocity(Vec3::zero()))
        .insert(Collider);

    // Add obstacle
    commands
        .spawn_bundle(SpriteBundle {
            material: materials.add(Color::rgb(1.0, 0.0, 0.0).into()),
            transform: Transform::from_xyz(100.0, 0.0, 10.0),
            sprite: Sprite::new(Vec2::new(30.0, 30.0)),
            ..Default::default()
        })
        .insert(Obstacle)
        .insert(Collider);
}

fn input_control(mut query: Query<&mut Velocity, With<Player>>, keyboard_input: Res<Input<KeyCode>>) {
    for mut velocity in query.iter_mut() {
        velocity.0 = Vec3::zero();
        if keyboard_input.pressed(KeyCode::W) {
            velocity.0.y += 2.0;
        }
        if keyboard_input.pressed(KeyCode::S) {
            velocity.0.y -= 2.0;
        }
        if keyboard_input.pressed(KeyCode::A) {
            velocity.0.x -= 2.0;
        }
        if keyboard_input.pressed(KeyCode::D) {
            velocity.0.x += 2.0;
        }
    }
}

fn movement(mut query: Query<(&Velocity, &mut Transform)>) {
    for (velocity, mut transform) in query.iter_mut() {
        transform.translation += velocity.0;
    }
}

fn collision_detection(mut player_query: Query<(&mut Player, &Transform), With<Player>>, obstacle_query: Query<&Transform, With<Obstacle>>) {
    for (mut player, player_transform) in player_query.iter_mut() {
        for obstacle_transform in obstacle_query.iter() {
            let collision = collide(
                player_transform.translation,
                Vec2::new(30.0, 30.0),
                obstacle_transform.translation,
                Vec2::new(30.0, 30.0),
            );
            if collision.is_some() {
                player.health -= 10;
            }
        }
    }
}

fn update_health(mut query: Query<&mut Player>) {
    for mut player in query.iter_mut() {
        if player.health <= 0 {
            player.health = 0;
        }
    }
}

fn check_game_over(mut game_state: ResMut<GameState>, query: Query<&Player>) {
    for player in query.iter() {
        if player.health <= 0 {
            game_state.game_over = true;
        }
    }
}

fn on_game_criteria(game_state: Res<GameState>) -> bool {
    game_state.in_game && !game_state.game_over
}

fn on_start_criteria(game_state: Res<GameState>) -> bool {
    !game_state.in_game && !game_state.game_over
}

fn on_game_over_criteria(game_state: Res<GameState>) -> bool {
    game_state.game_over
}

fn show_start_screen(mut game_state: ResMut<GameState>, keyboard_input: Res<Input<KeyCode>>) {
    if keyboard_input.just_pressed(KeyCode::Space) {
        game_state.in_game = true;
    }
}

fn show_game_over_screen(mut game_state: ResMut<GameState>, keyboard_input: Res<Input<KeyCode>>) {
    if keyboard_input.just_pressed(KeyCode::R) {
        game_state.in_game = true;
        game_state.game_over = false;
    }
}

