        <p>Are you sure you want to delete this note?</p>
        <button onClick={() => confirmed = true}>Yes</button>
        <button onClick={() => confirmed = false}>No</button>
      </div>
    ) || confirmed;
  }

  return (
    <div>
      <h1>Notes</h1>
      <div>
        <input 
          type="text" 
          value={newNote} 
          onInput={(e) => setNewNote(e.target.value)} 
        />
