// Generator for lazy loading posts
function* postGenerator(fetchMorePosts) {
  let batch;
  while ((batch = yield fetchMorePosts())) {
    yield batch;
  }
}

// Error Boundary component
const ErrorBoundary = function* ({ children }) {
  try {
    yield children;
  } catch {
    yield <div>Error loading content</div>;
  }
};

// Feed Component
const Feed = function* () {
  const state = useAppState();
  const gen = postGenerator(() => fetch('/api/more-posts').then(response => response.json()));

  socket.onmessage = ({ data }) => {
    const update = JSON.parse(data);
    if (update.type === 'newPost') {
      state.posts = [...state.posts, update.data];
    }
  };

  while (true) {
    yield (
      <ErrorBoundary>
        <div>
          {state.posts.map(post => <Post key={post.id} {...post} />)}
          <button onClick={() => {
            const { value } = gen.next();
            if (value) {
              state.posts = [...state.posts, ...value];
            }
          }}>Load More</button>
        </div>
      </ErrorBoundary>
    );
  }
};

