  const state = useAppState();
  const metrics = useEngagementMetrics();

  while (true) {
    yield (
      <div className="post">
        <p>{content}</p>
        <button onClick={() => {
          state.posts = state.posts.map(post => post.id === id ? { ...post, likes: post.likes + 1 } : post);
          metrics.likes++;
        }}>
          {likes} Likes
        </button>
        <CommentSection postId={id} comments={comments} />
      </div>
    );
  }
};

// CommentSection Component
const CommentSection = function* ({ postId, comments }) {
  const state = useAppState();
  const metrics = useEngagementMetrics();
  let newComment = Whatsup('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (newComment()) {
      state.posts = state.posts.map(post =>
        post.id === postId ? { ...post, comments: [...post.comments, newComment()] } : post
      );
      metrics.comments++;
      newComment('');
    }
  };

  while (true) {
    yield (
      <div className="comments">
        {comments.map((comment, index) => <p key={index}>{comment}</p>)}
        <form onSubmit={handleSubmit}>
          <input value={newComment()} onChange={e => newComment(e.target.value)} />
          <button type="submit">Comment</button>
        </form>
      </div>
    );
  }
};

