use cot::prelude::*;
use cot::auth::jwt::JWTAuth;
use cot::orm::{Model, fields};
use cot::middleware::{Validator, RateLimiter, RoleBasedAccessControl};
use cot::logging::setup_logging;
use cot::http::{HTTPException, ValidationError};
use serde::Deserialize;

#[derive(Clone)]
struct AppState {
    session: cot::orm::session::Session,
}

#[derive(Model, Deserialize)]
struct User {
    username: String,
    password: String,
    role: String,
}

#[derive(Model, Deserialize)]
struct JobListing {
    title: String,
    description: String,
    location: String,
    salary: Option<f64>,
    employer_id: i32,
}

async fn user_register_validator(user: &User) -> Result<(), ValidationError> {
    if user.password.len() < 8 {
        return Err(ValidationError::new("Password must be at least 8 characters long."));
    }
    if !["user", "employer"].contains(&user.role.as_str()) {
        return Err(ValidationError::new("Role must be either 'user' or 'employer'."));
    }
    Ok(())
}

async fn job_validator(job: &JobListing) -> Result<(), ValidationError> {
    if let Some(salary) = job.salary {
        if salary < 0.0 {
            return Err(ValidationError::new("Salary must be a positive number."));
        }
    }
    Ok(())
}

async fn register_user(state: AppState, request: Request) -> Result<Response, HTTPException> {
    let user: User = request.json().await?;
    user_register_validator(&user).await?;
    let session = state.session.clone();
    session.create(user).await?;
    Ok(Response::new("User registered successfully"))
}

async fn login_user(state: AppState, request: Request, auth: JWTAuth) -> Result<Response, HTTPException> {
    let credentials: User = request.json().await?;
    let session = state.session.clone();
    let mut users = session.filter(User::filter().eq("username", &credentials.username).eq("password", &credentials.password)).await?;
    if users.is_empty() {
        return Err(HTTPException::new(401, "Invalid credentials"));
    }
    let user = &users[0];
    let token = auth.encode(&json!({ "user_id": user.id, "role": user.role }))?;
    Ok(Response::new(token))
}

async fn create_job(state: AppState, request: Request, auth: JWTAuth) -> Result<Response, HTTPException> {
    let job: JobListing = request.json().await?;
    job_validator(&job).await?;
    let employer_claims = auth.verify(request.headers())?;
    let employer_id = employer_claims.get("user_id").unwrap().as_i64().unwrap() as i32;
    let role = employer_claims.get("role").unwrap().as_str().unwrap();

    if role != "employer" {
        return Err(HTTPException::new(403, "Only employers can create job listings"));
    }

    let session = state.session.clone();
    session.create(JobListing { employer_id, ..job }).await?;
    Ok(Response::new("Job listing created"))
}

async fn modify_job(state: AppState, request: Request, job_id: i32, auth: JWTAuth) -> Result<Response, HTTPException> {
    let employer_claims = auth.verify(request.headers())?;
    let role = employer_claims.get("role").unwrap().as_str().unwrap();

    if role != "employer" {
        return Err(HTTPException::new(403, "Only employers can modify job listings"));
    }

    let session = state.session.clone();
    if request.method() == Method::PUT {
        let job: JobListing = request.json().await?;
        job_validator(&job).await?;
        session.update(job_id, job).await?;
        Ok(Response::new("Job updated"))
    } else {
        session.delete::<JobListing>(job_id).await?;
        Ok(Response::new("Job deleted"))
    }
}

async fn search_jobs(state: AppState, request: Request) -> Result<Response, HTTPException> {
    let query = request.query();
    let mut filters = Vec::new();
    if let Some(location) = query.get("location") {
        filters.push(JobListing::filter().icon("location", location));
    }
    if let Some(salary_min) = query.get("salary_min") {
        filters.push(JobListing::filter().gt("salary", &salary_min.parse::<f64>().unwrap()));
    }
    if let Some(salary_max) = query.get("salary_max") {
        filters.push(JobListing::filter().lt("salary", &salary_max.parse::<f64>().unwrap()));
    }
    if let Some(keywords) = query.get("keywords") {
        filters.push(JobListing::filter().icon("description", keywords));
    }

    let session = state.session.clone();
    let jobs = session.filter(JobListing::filter().all(filters)).await?;
    Ok(Response::new(serde_json::to_string(&jobs)?))
}

