@app.route('/upload', methods=['POST'])
@login_required
def upload_file():
    form = UploadForm()
    if form.validate_on_submit():
        f = form.file.data
        filename = secure_filename(f.filename)
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        f.save(filepath)
        new_file = File(filename=filename, metadata=form.metadata.data, owner_id=current_user.id)
        db.session.add(new_file)
        db.session.commit()
        logger.info(f"File uploaded: {filename} by user: {current_user.username}")
        return redirect(url_for('index'))

@app.route('/download/<int:file_id>')
@login_required
def download_file(file_id):
    file = File.query.get(file_id)
    if not file or not can_access(file):
        abort(404 if not file else 403)
    return send_file(os.path.join(app.config['UPLOAD_FOLDER'], file.filename))

