import example.models.*;
import com.yahoo.elide.Elide;
import com.yahoo.elide.core.DataStore;
import com.yahoo.elide.core.dictionary.EntityDictionary;
import com.yahoo.elide.datastores.jpa.JpaDataStore;
import com.yahoo.elide.graphql.GraphQLApi;
import com.yahoo.elide.resources.DefaultOpaqueUserFunction;
import com.yahoo.elide.resources.ResourceConfig;
import com.yahoo.elide.security.audit.AuditLogger;
import com.yahoo.elide.security.User;
import com.yahoo.elide.spring.config.ElideConfigProperties;
import com.yahoo.elide.spring.controllers.GraphQLController;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.method.configuration.EnableGlobalMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityConfigurerAdapter;
import javax.persistence.EntityManagerFactory;
import javax.persistence.Persistence;

@EnableWebSecurity
@EnableGlobalMethodSecurity(prePostEnabled = true)
@Configuration
public class ElideConfig extends WebSecurityConfigurerAdapter {

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http.cors().and().csrf().disable()
                .authorizeRequests()
                .antMatchers("/api/graphql").hasAnyRole("ADMIN", "DOCTOR", "PATIENT")
                .and()
                .formLogin().permitAll()
                .and()
                .logout().permitAll();
    }

    @Bean
    public ElideConfigProperties elideConfigProperties() {
        ElideConfigProperties elideConfigProperties = new ElideConfigProperties();
        elideConfigProperties.getRoles().add("ADMIN");
        elideConfigProperties.getRoles().add("DOCTOR");
        elideConfigProperties.getRoles().add("PATIENT");
        return elideConfigProperties;
    }

    @Bean
    public Elide elide() {
        EntityManagerFactory emf = Persistence.createEntityManagerFactory("hospital-jpa");
        DataStore dataStore = new JpaDataStore(emf::createEntityManager);

        Elide elide = new Elide(new DefaultOpaqueUserFunction(), new SensitiveDataLoggingHook());
        elide.registerDataStore(dataStore);
        elide.registerCustomFilterExpression("checkAppointmentConflict",
                "(Appointment.startDateTime < :endDateTime AND Appointment.endDateTime > :startDateTime) != true");

        return elide;
    }

    @Bean
    public ResourceConfig resourceConfig(Elide elide) {
        ResourceConfig resourceConfig = new ResourceConfig();
        resourceConfig.register(new GraphQLApi(elide));
        resourceConfig.register(GraphQLController.class);
        return resourceConfig;
    }
}

